const body = $json.body ?? $json;
const clientToken = body.clientToken ?? '';
const amount = Number(body.amount ?? 0);
const currency = body.currency ?? 'COP';
const method = body.method ?? 'bancolombia_button';
const idempotencyKey = body.idempotencyKey ?? '';
const correlationId = body.correlationId ?? '';

if (!clientToken) {
  throw new Error('clientToken is required');
}

const paymentIntentId = `pi_${Date.now()}_${Math.random().toString(16).slice(2, 10)}`;
const providerReference = `bc_${Date.now()}_${Math.random().toString(16).slice(2, 10)}`;
const checkoutUrl = `https://pagos.bancolombia.com/checkout?reference=${providerReference}`;

return [{
  json: {
    success: true,
    paymentIntentId,
    provider: 'bancolombia',
    providerReference,
    checkoutUrl,
    amount,
    currency,
    method,
    idempotencyKey,
    correlationId,
    message: 'Intento de pago creado.'
  }
}];
